import React, { useState, useEffect, useRef } from 'react';
import './ChatbotV2.css';
import './ResultsTable.css';
import './Timestamp.css';
import './DataTable.css';
import MarkdownRenderer from './MarkdownRenderer';
import DataInsightsPieChart from './DataInsightsPieChart';

/* ======================================================
   CHATGPT-STYLE PROMPT GUARD (PRODUCTION SAFE)
====================================================== */

const CAR_BRANDS = [
  'suzuki','toyota','nissan','hyundai','kia','honda',
  'mg','skoda','renault','chevrolet','ford','mazda'
];

const CAR_KEYWORDS = [
  'car','cars','vehicle','vehicles','brand','brands',
  'buy','purchase','ownership','usage','sentiment',
  'compare','vs','review','consumer','profile',
  'media','lifestyle','dependency','transport'
];

// simple typo-tolerant matcher
const isNearMatch = (a, b) => {
  let mismatches = 0;
  for (let i = 0; i < Math.min(a.length, b.length); i++) {
    if (a[i] !== b[i]) mismatches++;
    if (mismatches > 2) return false;
  }
  return true;
};

const isValidCarPrompt = (query) => {
  if (!query) return false;
  const q = query.toLowerCase();
  const words = q.split(/\s+/);

  if (CAR_KEYWORDS.some(k => q.includes(k))) return true;
  if (CAR_BRANDS.some(b => q.includes(b))) return true;

  // typo handling
  for (const w of words) {
    for (const b of CAR_BRANDS) {
      if (isNearMatch(w, b)) return true;
    }
  }
  return false;
};

const getFriendlyFallbackMessage = () => `
I’m here to help with **affordable car insights in the UAE** 🚗

You can ask about:
• Car ownership & dependency  
• Brand comparisons (Suzuki vs Toyota)  
• Consumer profiles & usage  
• Purchase intent & sentiment  
• Media and lifestyle behavior  

👉 Try asking something related to cars.
`;

const sanitizeBotResponse = (text) => {
  if (!text) return text;

  const forbidden = [
    'cortex analyst',
    'semantic model',
    'data model',
    'not recognized',
    'no data available',
    'unable to provide',
    'not defined'
  ];

  if (forbidden.some(p => text.toLowerCase().includes(p))) {
    return getFriendlyFallbackMessage();
  }
  return text;
};

const shouldShowPieChart = (data) => {
  if (!Array.isArray(data) || data.length === 0) return false;
  const sample = data[0];
  return (
    Object.values(sample).some(v => typeof v === 'string') &&
    Object.values(sample).some(v => typeof v === 'number')
  );
};

/* ======================================================
   COMPONENT
====================================================== */

const ChatbotV2 = () => {
  const [messages, setMessages] = useState([
    {
      text: "Hello! I'm your AI Data Assistant. Ask me anything about affordable cars in the UAE.",
      sender: "bot",
      type: "text",
      timestamp: new Date()
    }
  ]);
  const [customQuery, setCustomQuery] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [expandedMessages, setExpandedMessages] = useState(new Set());
  const [showTechnicalInsights, setShowTechnicalInsights] = useState(false);
  const [latestTechnicalData, setLatestTechnicalData] = useState(null);
  const [activeTab, setActiveTab] = useState('sql');
  const messagesContainerRef = useRef(null);
  const chartRef = useRef(null);

  const dashboardQueries = [
    'What is the ownership of cars within the affordable segment?',
    'What car brands within the affordable segment do residents of the UAE consider?',
    'Which other brands are likely to be considered by Suzuki intenders?',
    'How does Suzuki sentiment compare with brands also considered?',
    'What is the profile of affordable car consumers?',
    'What is the car usage behavior of affordable car consumers?',
    'What is the level of dependency on cars among affordable segment consumers?',
    'How many consumers rely on public transport?',
    'How many consumers are intending to buy a car in the next 3–6 months?',
    'What are the lifestyle and media habits of affordable car consumers?'
  ];

  const scrollToBottom = () => {
    messagesContainerRef.current?.scrollTo({
      top: messagesContainerRef.current.scrollHeight,
      behavior: 'smooth'
    });
  };

  useEffect(scrollToBottom, [messages]);

  /* ===========================
     STREAMING RESPONSE
  ============================ */

  const handleStreamingResponse = async (query) => {
    try {
      const res = await fetch(
        `${process.env.REACT_APP_API_URL || 'http://localhost:3002/api/v1'}/chat/ask/stream`,
        {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ message: query })
        }
      );

      const reader = res.body.getReader();
      const decoder = new TextDecoder();
      let content = '';

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        const chunk = decoder.decode(value);
        if (!chunk.startsWith('data:')) continue;

        const payload = chunk.replace('data:', '').trim();
        if (payload === '[DONE]') break;

        const parsed = JSON.parse(payload);

        if (parsed.type === 'start') {
          setLatestTechnicalData({
            sql: parsed.cortexData?.sql,
            dataInsights: parsed.cortexData?.results || []
          });
        }

        if (parsed.type === 'chunk') {
          content += parsed.content || '';
          setMessages(prev => {
            const copy = [...prev];
            copy[copy.length - 1] = {
              text: sanitizeBotResponse(content),
              sender: 'bot',
              type: 'markdown',
              timestamp: new Date()
            };
            return copy;
          });
        }
      }
    } catch {
      setMessages(prev => [
        ...prev,
        {
          text: getFriendlyFallbackMessage(),
          sender: 'bot',
          type: 'markdown',
          timestamp: new Date()
        }
      ]);
    } finally {
      setIsProcessing(false);
    }
  };

  /* ===========================
     QUERY HANDLERS
  ============================ */

  const askQuery = (query) => {
    if (!isValidCarPrompt(query)) {
      setMessages(prev => [
        ...prev,
        { text: query, sender: 'user', type: 'text', timestamp: new Date() },
        {
          text: getFriendlyFallbackMessage(),
          sender: 'bot',
          type: 'markdown',
          timestamp: new Date()
        }
      ]);
      return;
    }

    setIsProcessing(true);
    setMessages(prev => [
      ...prev,
      { text: query, sender: 'user', type: 'text', timestamp: new Date() },
      { text: 'Thinking…', sender: 'bot', type: 'thinking', timestamp: new Date() }
    ]);

    handleStreamingResponse(query);
  };

  /* ===========================
     UI
  ============================ */

  return (
    <div className="chatbot-v2-container">
      <div className="sidebar">
        <h4>Frequently Asked Questions</h4>
        {dashboardQueries.map((q, i) => (
          <button
            key={i}
            disabled={isProcessing}
            onClick={() => askQuery(q)}
          >
            {q}
          </button>
        ))}
        <textarea
          value={customQuery}
          placeholder="Ask your own question…"
          onChange={e => setCustomQuery(e.target.value)}
          onKeyDown={e => e.key === 'Enter' && !e.shiftKey && askQuery(customQuery)}
        />
        <button disabled={isProcessing} onClick={() => askQuery(customQuery)}>
          Ask
        </button>
      </div>

      <div className="main-area">
        <div className="messages-container" ref={messagesContainerRef}>
          {messages.map((m, i) => (
            <div key={i} className={`message ${m.sender}`}>
              {m.type === 'markdown'
                ? <MarkdownRenderer content={m.text} />
                : <div>{m.text}</div>}

              {m.sender === 'bot' &&
                latestTechnicalData?.dataInsights &&
                shouldShowPieChart(latestTechnicalData.dataInsights) && (
                  <DataInsightsPieChart data={latestTechnicalData.dataInsights} />
                )}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default ChatbotV2;
